/* 
  CLIENT CODE (Runs on user's laptop):
  Takes the password from the input box, and asks the server if it's correct.
*/
fetch('https://api.myapp.com/login', { 
  method: 'POST', body: JSON.stringify({ pass: '123' }) 
});

/*
  SERVER CODE (Runs in Amazon AWS Data Center):
  Receives the '123' string, checks the secure database, and replies YES or NO.
*/
app.post('/login', (req, res) => {
  const isValid = checkDatabase(req.body.pass);
  res.send(isValid);
});
